/**
 * download-docs.js
 * Adds a "Download Docs" button to the MkDocs Material header.
 * On click: reads window.DANDORI_DOCS (generated by hooks/docs_bundle.py),
 * zips all markdown files with JSZip, and triggers a browser download.
 */

(function () {
  "use strict";

  const JSZIP_CDN = "https://cdnjs.cloudflare.com/ajax/libs/jszip/3.10.1/jszip.min.js";
  const ZIP_FILENAME = "dandori-docs.zip";

  function loadScript(src) {
    return new Promise(function (resolve, reject) {
      if (document.querySelector('script[src="' + src + '"]')) {
        resolve();
        return;
      }
      var s = document.createElement("script");
      s.src = src;
      s.onload = resolve;
      s.onerror = reject;
      document.head.appendChild(s);
    });
  }

  function getBundleUrl() {
    // Derive absolute URL from this script's own src — guaranteed correct on any subpath
    var scripts = document.querySelectorAll("script[src]");
    for (var i = 0; i < scripts.length; i++) {
      if (scripts[i].src.indexOf("download-docs") !== -1) {
        return scripts[i].src.replace("download-docs.js", "docs-bundle.js");
      }
    }
    // Fallback: relative to current page (works for flat sites)
    return "javascripts/docs-bundle.js";
  }

  function loadDocsBundle() {
    return new Promise(function (resolve, reject) {
      if (window.DANDORI_DOCS) {
        resolve(window.DANDORI_DOCS);
        return;
      }
      var bundleUrl = getBundleUrl();
      loadScript(bundleUrl)
        .then(function () {
          if (window.DANDORI_DOCS) {
            resolve(window.DANDORI_DOCS);
          } else {
            reject(new Error("docs-bundle.js loaded but DANDORI_DOCS not found"));
          }
        })
        .catch(reject);
    });
  }

  async function downloadAllDocs(btn) {
    btn.disabled = true;
    btn.textContent = "Zipping…";

    try {
      await loadScript(JSZIP_CDN);
      var docs = await loadDocsBundle();

      var zip = new JSZip(); // eslint-disable-line no-undef
      var folder = zip.folder("dandori-docs");

      Object.values(docs).forEach(function (page) {
        folder.file(page.filename, page.content);
      });

      var blob = await zip.generateAsync({ type: "blob" });
      var url = URL.createObjectURL(blob);
      var a = document.createElement("a");
      a.href = url;
      a.download = ZIP_FILENAME;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      setTimeout(function () { URL.revokeObjectURL(url); }, 10000);

      btn.textContent = "Downloaded!";
      setTimeout(function () {
        btn.textContent = "Download Docs";
        btn.disabled = false;
      }, 2000);
    } catch (err) {
      console.error("Download failed:", err);
      btn.textContent = "Error";
      btn.disabled = false;
    }
  }

  function createDownloadButton() {
    var btn = document.createElement("button");
    btn.textContent = "Download Docs";
    btn.title = "Download all documentation as markdown files (zip)";
    btn.style.cssText = [
      "display:inline-flex",
      "align-items:center",
      "gap:6px",
      "padding:6px 14px",
      "background:rgba(255,255,255,0.15)",
      "color:inherit",
      "border:1px solid rgba(255,255,255,0.35)",
      "border-radius:4px",
      "font-size:0.78rem",
      "font-weight:600",
      "letter-spacing:0.02em",
      "cursor:pointer",
      "transition:background 0.2s",
      "white-space:nowrap",
      "margin-left:8px",
    ].join(";");

    btn.addEventListener("mouseenter", function () {
      btn.style.background = "rgba(255,255,255,0.28)";
    });
    btn.addEventListener("mouseleave", function () {
      btn.style.background = "rgba(255,255,255,0.15)";
    });
    btn.addEventListener("click", function () {
      downloadAllDocs(btn);
    });

    return btn;
  }

  function injectHeaderButton() {
    // Material theme header: .md-header__inner contains logo + title + search + buttons
    var inner = document.querySelector(".md-header__inner");
    if (!inner) return;

    // Try to insert before search or at the end of the inner bar
    var source = inner.querySelector(".md-header__source");
    var btn = createDownloadButton();

    if (source) {
      inner.insertBefore(btn, source);
    } else {
      inner.appendChild(btn);
    }
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", injectHeaderButton);
  } else {
    injectHeaderButton();
  }

  // Re-inject on MkDocs Material SPA navigation
  document.addEventListener("DOMContentSwitch", injectHeaderButton);
})();
